def api_call(params):
    url = API + "?" + urllib.parse.urlencode(params)
    with urllib.request.urlopen(url, timeout=20) as r:
        return json.loads(r.read())

print(f"Subiendo {len(LEADS)} leads a Google Sheets...")
print("(los leads más viejos primero para que queden al final)\n")

errors = 0
# Send reversed so newest ends up on top
for i, lead in enumerate(reversed(LEADS)):
    try:
        params = {"action": "add", **lead}
        api_call(params)
        nombre = lead['Nombre']
        print(f"  ✓ {len(LEADS)-i}/{len(LEADS)}: {nombre}")
        time.sleep(0.4)
    except Exception as e:
        errors += 1
        print(f"  ✗ Error: {e}")

print(f"\n{'='*40}")
print(f"Listo! {len(LEADS)-errors} leads subidos, {errors} errores.")
if errors == 0:
    print("Abrí la app leads-meli.html y ya vas a ver todo.")
